@page "/catalog"
@using sv_423ca8c62eeb4bea9fefd40e1a7c9524.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-container">
    <!-- Left Sidebar -->
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        <div class="filter-section">
            <h4>Categories</h4>
            @if (_categories is not null)
            {
                @foreach (var category in _categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@(_selectedCategories.Contains(category))"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            }
        </div>

        <div class="filter-section">
            <h4>Price Range</h4>
            <div class="price-inputs">
                <input type="number" placeholder="Min" @bind="_minPrice" step="0.01" min="0" />
                <span>–</span>
                <input type="number" placeholder="Max" @bind="_maxPrice" step="0.01" min="0" />
            </div>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="_inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <main class="catalog-main">
        @if (_isLoading)
        {
            <div class="catalog-loading">
                <p>Loading products...</p>
            </div>
        }
        else if (_errorMessage is not null)
        {
            <div class="catalog-error">
                <p>@_errorMessage</p>
                <button class="btn btn-primary" @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="catalog-empty">
                <p>No products found. Try adjusting your filters.</p>
            </div>
        }
        else
        {
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="sort-control">
                    <label for="sort-select">Sort by:</label>
                    <select id="sort-select" @bind="_sortBy" @bind:after="LoadProducts">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="results-info">
                    Showing @((_result.Page - 1) * _result.PageSize + 1)–@(Math.Min(_result.Page * _result.PageSize, _result.TotalCount)) of @_result.TotalCount products
                </span>
            </div>

            <!-- Product Grid -->
            <div class="product-grid">
                @foreach (var product in _result.Items)
                {
                    <ProductCard Product="product"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />
                }
            </div>

            <!-- Pagination -->
            <nav class="pagination">
                <button class="btn btn-page"
                        disabled="@(_currentPage <= 1)"
                        @onclick="() => GoToPage(_currentPage - 1)">
                    Previous
                </button>

                @for (int i = 1; i <= TotalPages; i++)
                {
                    var pageNum = i;
                    <button class="btn btn-page @(pageNum == _currentPage ? "active" : "")"
                            @onclick="() => GoToPage(pageNum)">
                        @pageNum
                    </button>
                }

                <button class="btn btn-page"
                        disabled="@(_currentPage >= TotalPages)"
                        @onclick="() => GoToPage(_currentPage + 1)">
                    Next
                </button>
            </nav>
        }
    </main>
</div>

@code {
    [Parameter]
    public EventCallback<int> OnProductSelected { get; set; }

    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? _result;
    private bool _isLoading;
    private string? _errorMessage;

    private int TotalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategories();
        await LoadProducts();
    }

    private async Task LoadCategories()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            _categories = new List<string>();
        }
    }

    private async Task LoadProducts()
    {
        _isLoading = true;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                MinPrice: _minPrice,
                MaxPrice: _maxPrice,
                InStockOnly: _inStockOnly
            );

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            _isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(int productId)
    {
        await OnProductSelected.InvokeAsync(productId);
    }

    private void HandleAddToCart(int productId)
    {
        // Add to cart logic handled by parent or a cart service
    }
}

