toolArgs.file_text:
.catalog-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    border-right: 1px solid #e0e0e0;
    padding-right: 1.5rem;
}

.catalog-sidebar h3 {
    margin-top: 0;
}

.catalog-main {
    width: 75%;
    flex: 1;
}

.filter-section {
    margin-bottom: 1.5rem;
}

.filter-section h4 {
    margin-bottom: 0.5rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.4rem;
    cursor: pointer;
}

.price-inputs {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.price-inputs input {
    width: 80px;
    padding: 0.3rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-primary {
    background-color: #0d6efd;
    color: white;
}

.btn-primary:hover:not(:disabled) {
    background-color: #0b5ed7;
}

.btn-secondary {
    background-color: #6c757d;
    color: white;
}

.btn-secondary:hover:not(:disabled) {
    background-color: #5c636a;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.75rem;
    background: #f8f9fa;
    border-radius: 4px;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control select {
    padding: 0.3rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.results-info {
    color: #6c757d;
    font-size: 0.9rem;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.5rem;
}

.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.25rem;
    margin-top: 2rem;
}

.btn-page {
    background: #fff;
    border: 1px solid #dee2e6;
    padding: 0.4rem 0.75rem;
    border-radius: 4px;
    cursor: pointer;
}

.btn-page:hover:not(:disabled) {
    background: #e9ecef;
}

.btn-page.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.catalog-loading,
.catalog-error,
.catalog-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 300px;
    color: #6c757d;
}

.catalog-error {
    color: #dc3545;
}

